- (NSInteger)certMessageCount:(PLXPPollingHandler *)pollingHandler {
    return [PLXPCTMediatorTool certMessageCount]; 
}

- (BOOL)pollingUnlockIfNeed:(PLXPPollingHandler *)pollingHandler {
    if (self.pollingRunMode != PLPollingRunModeUnLock && self.pollingRunMode != PLPollingRunModeLockAndUnlock) {
        DLogTagInfo(kBLEKeyPollingTag, @"未开Polling解锁功能，返回,%d",self.pollingRunMode);
        return NO;
    }
    if (pollingHandler.unlockOperateTime != 0) {
        DLogTagInfo(kBLEKeyPollingTag, @"<PA>想解锁，但是没有出6秒的限制，返回");
        return NO;
    }
    if ((XPVehicleDoorLockState)StateSafeEnum([PLVehicleStateInstance shareInstance].fullVehicleStateDict[@"door"][@"driver_door_lock_st"]) == XPVehicleDoorLockStateUnlocked) {
        DLogTagInfo(kBLEKeyPollingTag, @"车辆是解锁状态，返回,%d", (XPVehicleDoorLockState)StateSafeEnum([PLVehicleStateInstance shareInstance].fullVehicleStateDict[@"door"][@"driver_door_lock_st"]));
        return NO;
    }
    if ((XPVehicleDoorLockState)StateSafeEnum([PLVehicleStateInstance shareInstance].fullVehicleStateDict[@"door"][@"driver_door_lock_st"]) == XPVehicleDoorLockStateDefault) {
        if (!self.isRemedy) {
            DLogTagInfo(kBLEKeyPollingTag, @"车辆是解锁未知状态，不兜底，返回,%d", (XPVehicleDoorLockState)StateSafeEnum([PLVehicleStateInstance shareInstance].fullVehicleStateDict[@"door"][@"driver_door_lock_st"]));
            return NO;
        }
    }
    if ((XPVehicleTempLockState)StateSafeEnum([PLVehicleStateInstance shareInstance].fullVehicleStateDict[@"door"][@"temp_lock_st"]) == XPVehicleTempLockStateActive) {
        DLogTagInfo(kBLEKeyPollingTag, @"车辆是临停状态,不解锁，返回,%d", (XPVehicleTempLockState)StateSafeEnum([PLVehicleStateInstance shareInstance].fullVehicleStateDict[@"door"][@"temp_lock_st"]));
        return NO;
    }

    if ((XPVehicleLeaveCarKeepPowerState)StateSafeEnum([PLVehicleStateInstance shareInstance].fullVehicleStateDict[@"door"][@"leave_car_keep_power"]) == XPVehicleLeaveCarKeepPowerStateOff ||
        (XPVehicleLeaveCarKeepPowerState)StateSafeEnum([PLVehicleStateInstance shareInstance].fullVehicleStateDict[@"door"][@"leave_car_keep_power"])  == XPVehicleLeaveCarKeepPowerStateDefault) {
        // B件蓝牙会出现车辆状态不返回的情况，为了不影响polling开启，当设防状态未返回时，也允许polling
        if ((XPAlarmState)StateSafeEnum([PLVehicleStateInstance shareInstance].fullVehicleStateDict[@"polling"][@"alarmState"]) == XPAlarmStateDisarmed ||
            (XPAlarmState)StateSafeEnum([PLVehicleStateInstance shareInstance].fullVehicleStateDict[@"polling"][@"alarmState"])  == XPAlarmStateRemind || (XPAlarmState)StateSafeEnum([PLVehicleStateInstance shareInstance].fullVehicleStateDict[@"polling"][@"alarmState"])  == XPAlarmStateAlarm){
            DLogTagInfo(kBLEKeyPollingTag, @"<PA>想解锁，但车辆不是设防状态，返回,%d", (XPAlarmState)StateSafeEnum([PLVehicleStateInstance shareInstance].fullVehicleStateDict[@"polling"][@"alarmState"]) );
            return NO;
        }
        if ((XPAlarmState)StateSafeEnum([PLVehicleStateInstance shareInstance].fullVehicleStateDict[@"polling"][@"alarmState"]) == XPAlarmStateDefault && !self.isRemedy){
            DLogTagInfo(kBLEKeyPollingTag, @"车辆是设防未知状态，返回,%d",  (XPAlarmState)StateSafeEnum([PLVehicleStateInstance shareInstance].fullVehicleStateDict[@"polling"][@"alarmState"]));
            return NO;
        }
    }

    if (self.pollingUnlockTryCount >= 3) {
        DLogTagInfo(kBLEKeyPollingTag, @"<PA>想解锁，但超过三次，返回");
        return NO;
    }

    NSDate *currentTime = [NSDate date];
    if(self.prevUnlockCommandTime && [[self.prevUnlockCommandTime dateByAddingTimeInterval:pollingHandler.pollingUnlockInterval] compare:currentTime] == NSOrderedDescending){
        DLogTagInfo(kBLEKeyPollingTag, @"<PA>想解锁，但是没有出上一次解锁间隔限制，返回");
        return NO;
    }

    return YES;
}

- (BOOL)pollingLockIfNeed:(PLXPPollingHandler *)pollingHandler {
    if (self.pollingRunMode != PLPollingRunModeLockAndUnlock && self.pollingRunMode != PLPollingRunModeLock) {
        DLogTagInfo(kBLEKeyPollingTag, @"启用的mode1,不做闭锁");
        return NO;
    }
    if (self.isDoorOpen) {
        DLogTagInfo(kBLEKeyPollingTag, @"车辆是开门状态，不执行polling闭锁");
        return NO;
    }
    if (pollingHandler.lockOperateTime != 0) {
        DLogTagInfo(@"kBLEKeyPollingTag", @"<PA>想闭锁，但是没有出6秒的限制，返回,剩余");
        return NO;
    } 

    XPVehicleDoorLockState doorState = (XPVehicleDoorLockState)StateSafeEnum([PLVehicleStateInstance shareInstance].fullVehicleStateDict[@"door"][@"driver_door_lock_st"]);
    if (doorState == XPVehicleDoorLockStateLocked || doorState == XPVehicleDoorLockStateDefault) {
        return NO;
    }
    if (self.pollingLockTryCount >= 3) {
        DLogTagInfo(kBLEKeyPollingTag, @"<PA>想闭锁，但是超过3次，返回");
        return NO ;
    }

    NSDate *currentTime = [NSDate date];
    if(self.prevLockCommandTime && [[self.prevLockCommandTime dateByAddingTimeInterval:pollingHandler.pollingLockInterval] compare:currentTime] == NSOrderedDescending){
        DLogTagInfo(kBLEKeyPollingTag, @"<PA>想闭锁，但是没有出上一次闭锁间隔限制，返回");
        return NO;
    }

    return YES;
}

