import Foundation

/// 档位状态
@objc(XPGearState)
public enum GearState: Int, Codable, NamedEnum, CustomStringConvertible {
    case `default` = -1
    case invalid = 0
    case D = 1
    case N = 2
    case R = 3
    case P = 4

    public var name: String {
        switch self {
        case .default: return "Default"
        case .invalid: return "invalid"
        case .D: return "D"
        case .N: return "N"
        case .R: return "R"
        case .P: return "P"
        default: return ""
        }
    }

