    REGISTERPANELCLASS(D22DataParser);
    REGISTERPANELCLASS(E28aDataParser);
    REGISTERPANELCLASS(E28DataParser);
    REGISTERPANELCLASS(BleKeyV3DataParser);
}

BaseDataParser * createDataParser(const string vehicleCode) {
    string className = vehicleCodeClassMap[vehicleCode];

    if (className.empty()) {
        className = "BleKeyV3DataParser";
    }
    XP_LOG_INFO("CPPBle", "createDataParser className: %{public}s", className.c_str());

