    guard let code = msgContent["code"] as? Int else { return }
    guard let msg = msgContent["msg"] as? String else { return }

    if code == 9 { // MQTTResponseCode.powerOn.rawValue
        NotificationCenter.default.post(name: VehicleNotification.kCameraErrorNotification, object: msg)
    }
}

func updateCamearState(cameraStr:[String : Any], msg:MQTTMessageInfo){
    guard let state = CameraStateChangedNotiObject.yy_model(with: cameraStr) else { return }
    state.vin = msg.vin
    NotificationCenter.default.post(name: VehicleNotification.CameraStateChanged, object: nil, userInfo: ["camera": state])
}

