public func didReceiveSubscribTopicMessage(topic: String, msg: [String : Any]) {
    Log.i("XiaopengTCPConnection didReceiveSubscribTopicMessage topic:\(topic)")

    if let msg_content : [String : Any] = msg["msg_content"] as? [String : Any], msg["vin"] as? String ?? "" == vin  {
        if let state = parseContentMsg(msg_content: msg_content) {
            state.vin = vin
            onReceivedVehicleState(vehicleState: state)
        }
        else {
            let code = msg_content["code"] as? Int
            if (code != MQTTResponseCode.success.rawValue) {
                if (code == MQTTResponseCode.carRepair.rawValue) {
                    openRepairMode()
                }

                if (code == MQTTResponseCode.offline.rawValue) {
                    self.presenter?.setVehicleOnline(online: false);
                }
            }
        }
    }

    // 处理 mqtt 消息
    handleMqttMessage(msg: msg)
}

