public func didReceiveMessage(topic: String, msg: [String : Any]) {
    Log.i("XiaopengTCPConnection didReceiveMessage topic:\(topic)")
    if let content : [String : Any] = msg["content"] as? [String : Any] {
        let action = parseContentAction(content: content)
        switch action {
        case .repairModeComplete:
            closeRepairMode()
            break
        default:
            break
        }
    }
}

