import Foundation


/// 数字驾驶信息
@objc(XPDigitalDrive)
public class DigitalDrive: NSObject, Codable {
    /// 车辆P档开始时间，默认值为-1。当车辆切换为非P档时，返回-1
    public var p_shift_st: Int64? = nil

    /// 以正北偏移的角度（°）,当正北时为0
    public var angle: Float? = nil

    /// 纬度
    public var latitude: Double? = nil

    /// 经度
    public var longitude: Double? = nil
}

